// ⚠️ Default sort is lexicographic!
nums.sort();              // [1, 1, 3, 4, 5] (works for small ints)

// Always use comparator for numbers
nums.sort((a, b) => a - b);  // ascending
nums.sort((a, b) => b - a);  // descending

// Non-mutating copy
const sorted = [...nums].sort((a, b) => a - b);

